#include <bits/stdc++.h>
using namespace std;
int main(){
    int n,m;char a='A'-1,b=char(0);
    string str[1003];
    cin>>n>>m;
    for(int i=1;i<=n;i++){
        cin>>str[i];
        for(int j=0;j<m;j++)
            if(str[i][j]!='#' && str[i][j]>a)a=str[i][j];
    }
    for(int i=1;i<=n;i++){
    	for(int j=0;j<m;j++){
    		if(str[i][j]==a){
    			if(i>1 && str[i-1][j]>b && str[i-1][j]!='#')b=str[i-1][j];
    			if(j>0 && str[i][j-1]>b && str[i][j-1]!='#')b=str[i][j-1];
    			if(i<n && str[i+1][j]>b && str[i+1][j]!='#')b=str[i+1][j];
    			if(j<m-1 && str[i][j+1]>b && str[i][j+1]!='#')b=str[i][j+1];
			}
		}
	}
    cout<<a;
    if(b!=0 && b!=a)cout<<b;
    return 0;
}
